ranked_unbound AS (
  SELECT
    m.id,
    m.code,
    ROW_NUMBER() OVER (PARTITION BY m.code ORDER BY m.id DESC) AS rn
  FROM materials m
  JOIN codes c ON c.code = m.code
  WHERE m.restaurant_brand_id IS NULL
)
DELETE FROM materials m
USING ranked_unbound r
WHERE m.id = r.id
  AND r.rn > 1;

