DELETE FROM materials m
USING target_brand tb, codes c
WHERE m.code = c.code
  AND m.restaurant_brand_id IS NULL
  AND EXISTS (
    SELECT 1
    FROM materials x
    WHERE x.code = m.code
      AND x.restaurant_brand_id = tb.brand_id
  );

