UPDATE materials m
SET restaurant_brand_id = tb.brand_id
FROM target_brand tb
JOIN codes c ON TRUE
WHERE c.code = m.code
  AND m.restaurant_brand_id IS NULL
  AND NOT EXISTS (
    SELECT 1
    FROM materials x
    WHERE x.code = m.code
      AND x.restaurant_brand_id = tb.brand_id
  );

COMMIT;
